import{_ as e,o as d,c as r,ag as o}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"快捷键一览","description":"","frontmatter":{},"headers":[],"relativePath":"reference/shortcuts.md","filePath":"reference/shortcuts.md"}'),a={name:"reference/shortcuts.md"};function c(h,t,l,n,i,s){return d(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="快捷键一览" tabindex="-1">快捷键一览 <a class="header-anchor" href="#快捷键一览" aria-label="Permalink to &quot;快捷键一览&quot;">​</a></h1><blockquote><p>macOS 用 <strong>Cmd</strong> 替代 <strong>Ctrl</strong>；下表以 Windows/Linux 写法为准。</p></blockquote><hr><h2 id="全局快捷键" tabindex="-1">全局快捷键 <a class="header-anchor" href="#全局快捷键" aria-label="Permalink to &quot;全局快捷键&quot;">​</a></h2><p>任意界面下均可触发，无需焦点落在特定区域。</p><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl+N</code></td><td>新建草稿分栏并选中</td></tr><tr><td><code>Ctrl+Shift+T</code></td><td>复活最近关闭的分栏</td></tr><tr><td><code>Ctrl+P</code></td><td>打开文件搜索面板</td></tr><tr><td><code>Ctrl+`</code></td><td>开关底部终端面板</td></tr></tbody></table><hr><h2 id="文件树快捷键" tabindex="-1">文件树快捷键 <a class="header-anchor" href="#文件树快捷键" aria-label="Permalink to &quot;文件树快捷键&quot;">​</a></h2><p>焦点在左侧文件树区域时生效。</p><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl+C</code></td><td>复制选中的文件/目录</td></tr><tr><td><code>Ctrl+X</code></td><td>剪切选中的文件/目录</td></tr><tr><td><code>Ctrl+V</code></td><td>粘贴到当前选中项所在目录</td></tr><tr><td><code>Delete</code></td><td>删除选中的文件/目录</td></tr></tbody></table><blockquote><p><strong>说明：</strong> 右键菜单中的&quot;重命名&quot;条目显示 <code>F2</code> 提示，但 F2 键盘直接触发功能尚在开发中，目前请通过右键菜单执行重命名操作。</p></blockquote><hr><h2 id="编辑器快捷键" tabindex="-1">编辑器快捷键 <a class="header-anchor" href="#编辑器快捷键" aria-label="Permalink to &quot;编辑器快捷键&quot;">​</a></h2><p>代码编辑器（Monaco 编辑器）中生效。</p><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl+S</code></td><td>保存当前文件</td></tr></tbody></table><blockquote><p>Monaco 编辑器本身还内置了大量通用编辑快捷键（如代码折叠、跳转定义等），可在编辑器右键菜单的&quot;命令面板&quot;中查看完整列表。</p></blockquote><hr><h2 id="文本编辑通用快捷键" tabindex="-1">文本编辑通用快捷键 <a class="header-anchor" href="#文本编辑通用快捷键" aria-label="Permalink to &quot;文本编辑通用快捷键&quot;">​</a></h2><p>由操作系统或底层控件提供，可在输入框等文本区域直接使用。</p><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Ctrl+C</code></td><td>复制选中文本</td></tr><tr><td><code>Ctrl+X</code></td><td>剪切选中文本</td></tr><tr><td><code>Ctrl+V</code></td><td>粘贴文本</td></tr><tr><td><code>Ctrl+A</code></td><td>全选</td></tr><tr><td><code>Ctrl+Z</code></td><td>撤销</td></tr></tbody></table><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/reference/faq.html">常见问题</a> — 使用中的高频疑问</li><li><a href="/docs/reference/troubleshooting.html">故障排查</a> — 遇到问题时的处理指引</li></ul>',23)])])}const p=e(a,[["render",c]]);export{u as __pageData,p as default};
